#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <assert.h>

// 宏定义：用于 128 位向量化访存
#define FLOAT4(value) (reinterpret_cast<float4 *>(&(value))[0])
#define HALF2(value) (reinterpret_cast<half2 *>(&(value))[0])
#define LDST128BITS(value) (reinterpret_cast<float4 *>(&(value))[0])

// --- LeetCUDA Kernels ---

__global__ void add_f32(float *a, float *b, float *c, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < N) c[idx] = a[idx] + b[idx];
}

__global__ void add_f32x4(float *a, float *b, float *c, int N) {
    int idx = 4 * (blockIdx.x * blockDim.x + threadIdx.x);
    if (idx < N) {
        float4 reg_a = FLOAT4(a[idx]);
        float4 reg_b = FLOAT4(b[idx]);
        float4 reg_c;
        reg_c.x = reg_a.x + reg_b.x;
        reg_c.y = reg_a.y + reg_b.y;
        reg_c.z = reg_a.z + reg_b.z;
        reg_c.w = reg_a.w + reg_b.w;
        FLOAT4(c[idx]) = reg_c;
    }
}

__global__ void add_f16(half *a, half *b, half *c, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < N) c[idx] = __hadd(a[idx], b[idx]);
}

__global__ void add_f16x2(half *a, half *b, half *c, int N) {
    int idx = 2 * (blockIdx.x * blockDim.x + threadIdx.x);
    if (idx < N) {
        half2 reg_a = HALF2(a[idx]);
        half2 reg_b = HALF2(b[idx]);
        half2 reg_c = __hadd2(reg_a, reg_b);
        HALF2(c[idx]) = reg_c;
    }
}

__global__ void add_f16x8(half *a, half *b, half *c, int N) {
    int idx = 8 * (blockIdx.x * blockDim.x + threadIdx.x);
    if (idx + 7 < N) {
        half2 reg_a_0 = HALF2(a[idx + 0]); half2 reg_a_1 = HALF2(a[idx + 2]);
        half2 reg_a_2 = HALF2(a[idx + 4]); half2 reg_a_3 = HALF2(a[idx + 6]);
        half2 reg_b_0 = HALF2(b[idx + 0]); half2 reg_b_1 = HALF2(b[idx + 2]);
        half2 reg_b_2 = HALF2(b[idx + 4]); half2 reg_b_3 = HALF2(b[idx + 6]);
        HALF2(c[idx + 0]) = __hadd2(reg_a_0, reg_b_0);
        HALF2(c[idx + 2]) = __hadd2(reg_a_1, reg_b_1);
        HALF2(c[idx + 4]) = __hadd2(reg_a_2, reg_b_2);
        HALF2(c[idx + 6]) = __hadd2(reg_a_3, reg_b_3);
    } else {
        for (int i = 0; idx + i < N; i++) c[idx + i] = __hadd(a[idx + i], b[idx + i]);
    }
}

__global__ void add_f16x8_pack(half *a, half *b, half *c, int N) {
    int idx = 8 * (blockIdx.x * blockDim.x + threadIdx.x);
    half pack_a[8], pack_b[8], pack_c[8];
    if (idx + 7 < N) {
        LDST128BITS(pack_a[0]) = LDST128BITS(a[idx]);
        LDST128BITS(pack_b[0]) = LDST128BITS(b[idx]);
        #pragma unroll
        for (int i = 0; i < 8; i += 2) {
            HALF2(pack_c[i]) = __hadd2(HALF2(pack_a[i]), HALF2(pack_b[i]));
        }
        LDST128BITS(c[idx]) = LDST128BITS(pack_c[0]);
    } else {
        for (int i = 0; idx + i < N; i++) c[idx + i] = __hadd(a[idx + i], b[idx + i]);
    }
}

extern "C" void cuda_kernel(void *a, void *b, void *c, int size, int op_type) {
    switch(op_type) {
        case 0: // f32
            add_f32<<<(size + 255) / 256, 256>>>((float*)a, (float*)b, (float*)c, size);
            break;
        case 1: // f32x4
            add_f32x4<<<(size/4 + 255) / 256, 256>>>((float*)a, (float*)b, (float*)c, size);
            break;
        case 2: // f16
            add_f16<<<(size + 255) / 256, 256>>>((half*)a, (half*)b, (half*)c, size);
            break;
        case 3: // f16x2
            add_f16x2<<<(size/2 + 255) / 256, 256>>>((half*)a, (half*)b, (half*)c, size);
            break;
        case 4: // f16x8
            add_f16x8<<<(size/8 + 255) / 256, 256>>>((half*)a, (half*)b, (half*)c, size);
            break;
        case 5: // f16x8_pack
            add_f16x8_pack<<<(size/8 + 255) / 256, 256>>>((half*)a, (half*)b, (half*)c, size);
            break;
    }
}

